                btns.push('<button class="btn btn-secondary btn-sm" onclick="showDeviceInfoInline(\'' + d.ip + '\')">信息</button>');
                // Add "引导" button for new devices
            } else {
                btns.push('<button class="btn btn-primary btn-sm" onclick="connectDevice(\'' + d.ip + '\')">连接</button>');
            }
            // Add modify IP button for all devices
            btns.push('<button class="btn btn-warning btn-sm" onclick="modifyIpPrompt(\'' + (d.mac || '') + '\',\'' + (d.ip || '') + '\')">修改IP</button>');
            btns.push('<button class="btn btn-danger btn-sm" onclick="deleteDevice(\'' + (d.mac || d.ip) + '\')">删除</button>');
            return '<div class="actions">' + btns.join('') + '</div>';
        }
        // Device Actions
        function connectDevice(ip) {
            addLog('info', '正在连接设备: ' + ip);
            // 先获取 credentials
            apiGet('/api/v1/ptz/devices/' + ip + '/credentials').then(function(creds) {
                var username = (creds && creds.success) ? creds.username : 'admin';
                var password = (creds && creds.success) ? creds.password : '';
                var port = (creds && creds.success) ? (creds.port || 80) : 80;

                // 再调用 connect API
                apiPost('/api/v1/devices/' + ip + '/connect', { username: username, password: password, port: port }).then(function(result) {
                    if (result && result.success) {
                        showToast('success', '设备已连接: ' + ip);
                        addLog('success', result.message || '连接成功');
                        refreshDevices();
                        refreshPtzDeviceList();
                        refreshAdvancedDeviceSelectors();
