@api_router.get("/ptz/devices/{ip}/credentials")
async def get_ptz_device_credentials(ip: str):
    """获取设备凭据（用于 WASM SDK 登录）
    先查内存，再回退读 data/devices/{MAC}.json
    """
    ptz_mgr = _managers.get("ptz_manager")
    if ptz_mgr:
        creds = ptz_mgr._credentials.get(ip)
        if creds:
            return {
                "success": True,
                "ip": ip,
                "username": creds.get("username", "admin"),
                "password": creds.get("password", ""),
                "port": creds.get("port", 80),
            }
    # 回退：从 config_writer 读取单设备配置文件
    try:
        from src.advanced.config_writer import load_device_config
        from src.core.ptz_manager import PTZManager
        # 通过 IP 反查 MAC
        if ptz_mgr:
            for dev_ip, c in ptz_mgr._credentials.items():
                if dev_ip == ip and c.get("mac"):
                    config = load_device_config(c["mac"])
                    if config:
                        return {"success": True, "ip": ip, "username": config.username, "password": config.password, "port": config.port}
            # 从存储设备列表反查
            for dev in ptz_mgr.list_stored_devices():
                if dev.get("ip") == ip and dev.get("mac"):
                    config = load_device_config(dev["mac"])
                    if config:
                        return {"success": True, "ip": ip, "username": config.username, "password": config.password, "port": config.port}
        # 从 SADP 发现缓存反查
        if ptz_mgr:
            for dev in ptz_mgr.get_discovered_devices():
                if dev.get("ip") == ip and dev.get("mac"):
                    config = load_device_config(dev["mac"])
                    if config:
                        return {"success": True, "ip": ip, "username": config.username, "password": config.password, "port": config.port}
    except Exception:
        pass
    return {"success": False, "message": "凭据不存在"}

