            print(f"  API: {json.dumps(r,ensure_ascii=False)[:80]}")
            await page.wait_for_timeout(3000)
        await page.screenshot(path=f"{DIR}/e2e2_03_connected.png")

        # 4. 检查状态
        state = await page.evaluate("""
            () => ({
                connectedDevice: window.connectedDevice ? window.connectedDevice.ip : null,
                bLoggedIn: window.g_bLoggedIn2,
                bPlaying: window.g_bPlaying2,
            })
        """)
        print(f"[4] 状态: {json.dumps(state)}")

        # 5. 切主控台，等视频
        btns = await page.query_selector_all("button.nav-btn")
        if len(btns) >= 3:
            await btns[2].click()
            await page.wait_for_timeout(2000)
        print("[5] 等待视频(20s)...")
        await page.wait_for_timeout(20000)
        await page.screenshot(path=f"{DIR}/e2e2_04_video.png")

        # 6. 检查canvas
        canvas = await page.evaluate("""
            () => {
                const c = document.getElementById('divPlugin_playCanvas0');
                if (!c) return {found:false};
                const ctx = c.getContext('2d');
                const w=c.width, h=c.height;
                if (w===0||h===0) return {found:true,w,h,content:false};
                try {
                    const d = ctx.getImageData(0,0,w,h).data;
                    let nb=0, tot=d.length/4;
                    for(let i=0;i<d.length;i+=4) if(d[i]>10||d[i+1]>10||d[i+2]>10) nb++;
                    return {found:true,w,h,content:nb>tot*0.01,ratio:(nb/tot*100).toFixed(2)+'%'};
                } catch(e) { return {found:true,w,h,content:false,err:e.message}; }
            }
        """)
        print(f"[6] Canvas: {json.dumps(canvas)}")

        # 7. WASM错误
        errors = [m for m in msgs if "error" in m.lower() and "wasm" in m.lower()]
        ws_msgs = [m for m in msgs if "websocket" in m.lower() or "ws " in m.lower()]
        print(f"[7] WASM errors: {len(errors)}")
        for e in errors[:5]: print(f"  {e}")
        print(f"    WS msgs: {len(ws_msgs)}")
        for w in ws_msgs[:5]: print(f"  {w}")

        # 8. 断开
        btns = await page.query_selector_all("button.nav-btn")
        if len(btns) >= 2:
            await btns[1].click()
            await page.wait_for_timeout(1500)
        for btn in await page.query_selector_all("button"):
            try:
                text = await btn.inner_text()
                if "断开" in text:
                    await btn.click()
                    print("[8] 点击断开")
                    await page.wait_for_timeout(3000)
                    break
            except: continue
        await page.screenshot(path=f"{DIR}/e2e2_05_disconnected.png")

        # 9. 断开后状态
        state2 = await page.evaluate("""
            () => ({
                connectedDevice: window.connectedDevice ? window.connectedDevice.ip : null,
                bLoggedIn: window.g_bLoggedIn2,
                bPlaying: window.g_bPlaying2,
            })
        """)
        print(f"[9] 断开后: {json.dumps(state2)}")

        await browser.close()

    print("\n" + "="*50)
    print(f"RESULT: Canvas={json.dumps(canvas)}")
    print(f"  Connected={json.dumps(state)}")
    print(f"  Disconnected={json.dumps(state2)}")

asyncio.run(run())

