"""E2E: szAuth + video test"""
import asyncio, json
from playwright.async_api import async_playwright

async def run():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True)
        page = await browser.new_page(viewport={"width":1920,"height":1080})

        errors = []
        page.on("pageerror", lambda e: errors.append(str(e)[:100]))
        msgs = []
        page.on("console", lambda m: msgs.append({"type": m.type, "text": m.text[:150]}))
        ws_urls = []
        page.on("websocket", lambda ws: ws_urls.append(ws.url))

        await page.goto("http://localhost:8000", timeout=15000)
        await page.wait_for_load_state("networkidle", timeout=15000)

        if errors:
            print(f"JS Errors: {errors[:3]}")

        # Connect + login
        r = await page.evaluate("""async () => {
            const r = await fetch('/api/v1/devices/192.168.5.72/connect', {
                method:'POST', headers:{'Content-Type':'application/json'},
                body: JSON.stringify({username:'admin',password:'Nftw1357',port:80})
            });
            return await r.json();
        }""")
        await page.evaluate("""() => {
            window.connectedDevice = {ip:'192.168.5.72',port:80,username:'admin',password:'Nftw1357'};
        }""")
        result = await page.evaluate("""() => {
            if (typeof clickLogin2 === 'function') { clickLogin2(); return 'ok'; }
            return 'not found';
        }""")
        print(f"[1] Login: {result}")

        await page.wait_for_timeout(12000)

        state = await page.evaluate("""() => ({
            loggedIn: window.g_bLoggedIn2,
            szAuth: (window.WebVideoCtrl && window.WebVideoCtrl.w_deviceSet.length > 0) ? window.WebVideoCtrl.w_deviceSet[0].szAuth.substring(0,20) : 'N/A',
            wsPort: window.g_iWebSocketPort,
        })""")
        print(f"[2] State: {json.dumps(state)}")

        print("[3] Waiting 20s for video...")
        await page.wait_for_timeout(20000)

        canvas = await page.evaluate("""() => {
            var c = document.querySelector('canvas');
            if (!c) return {found:false};
            var ctx = c.getContext('2d');
            var d = ctx.getImageData(0,0,c.width,c.height).data;
            var nz = 0;
            for (var i=0;i<d.length;i+=40) { if(d[i]>0||d[i+1]>0||d[i+2]>0) nz++; }
            return {found:true, w:c.width, h:c.height, content:nz>100, nz:nz};
        }""")
        print(f"[4] Canvas: {json.dumps(canvas)}")
        print(f"[5] WS URLs: {ws_urls}")

        for m in msgs:
            t = m["text"].lower()
            if any(k in t for k in ["error","1008","szauth","token","play","wasm","start"]):
                mt = m["type"]
                mx = m["text"]
                print(f"  {mt}: {mx[:120]}")

        await browser.close()

