"""E2E: Video stream debug - check WS frames + WASM status"""
import asyncio, json
from playwright.async_api import async_playwright

async def run():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True)
        page = await browser.new_page(viewport={"width":1920,"height":1080})

        ws_events = []
        def on_ws(ws):
            ws.on("framereceived", lambda r: ws_events.append({"dir":"recv","len":len(r) if isinstance(r,(bytes,bytearray)) else len(str(r)),"type":"bin" if isinstance(r,(bytes,bytearray)) else "txt"}))
            ws.on("framesent", lambda r: ws_events.append({"dir":"sent","len":len(r) if isinstance(r,(bytes,bytearray)) else len(str(r))}))
            ws.on("socketerror", lambda e: ws_events.append({"dir":"error","msg":str(e)[:50]}))
            ws.on("close", lambda: ws_events.append({"dir":"closed"}))
        page.on("websocket", on_ws)

        msgs = []
        page.on("console", lambda m: msgs.append(m.text[:200]))

        await page.goto("http://localhost:8000", timeout=15000)
        await page.wait_for_load_state("networkidle", timeout=15000)

        # Login
        await page.evaluate("""async () => {
            await fetch('/api/v1/devices/192.168.5.72/connect', {
                method:'POST', headers:{'Content-Type':'application/json'},
                body: JSON.stringify({username:'admin',password:'Nftw1357',port:80})
            });
        }""")
        await page.evaluate("""() => {
            window.connectedDevice = {ip:'192.168.5.72',port:80,username:'admin',password:'Nftw1357'};
        }""")
        await page.evaluate("""() => { clickLogin2(); }""")

        # Wait for login + token + play
        await page.wait_for_timeout(15000)

        # Check szAuth
        szAuth = await page.evaluate("""() => {
            var ds = window.WebVideoCtrl ? window.WebVideoCtrl.w_deviceSet : [];
            return ds.length > 0 ? ds[0].szAuth.substring(0,20) : 'N/A';
        }""")
        print(f"[1] szAuth: {szAuth}")

        # Wait more for video
        await page.wait_for_timeout(15000)

        # WS events summary
        recv_count = sum(1 for e in ws_events if e.get("dir")=="recv")
        recv_bin = sum(1 for e in ws_events if e.get("dir")=="recv" and e.get("type")=="bin")
        recv_txt = sum(1 for e in ws_events if e.get("dir")=="recv" and e.get("type")=="txt")
        total_recv_bytes = sum(e.get("len",0) for e in ws_events if e.get("dir")=="recv")
        print(f"[2] WS: {recv_count} recv ({recv_bin} binary, {recv_txt} text), {total_recv_bytes} bytes")

        # Canvas check
        canvas = await page.evaluate("""() => {
            var c = document.querySelector('canvas');
            if (!c) return {found:false};
            return {found:true, w:c.width, h:c.height};
        }""")
        print(f"[3] Canvas: {json.dumps(canvas)}")

        # WASM logs
        for m in msgs:
            if any(k in m.lower() for k in ["error","1008","play","decode","video","render","wasm","szauth","start"]):
                print(f"  LOG: {m[:150]}")

        await browser.close()

asyncio.run(run())

